import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"55. Hours Of Work","description":"","frontmatter":{"title":"55. Hours Of Work","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","shift-work","employment","classifications"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/55-hours-of-work.md","filePath":"ebas/mspp/hours-of-work/55-hours-of-work.md"}'),s={name:"ebas/mspp/hours-of-work/55-hours-of-work.md"};function n(i,e,h,l,p,d){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_55-hours-of-work" tabindex="-1">55. Hours Of Work <a class="header-anchor" href="#_55-hours-of-work" aria-label="Permalink to &quot;55. Hours Of Work&quot;">​</a></h1><p><strong>55.1</strong> Ordinary Hours of Work (Full-time)</p><p><strong>a.</strong> The ordinary hours of work shall be 38 hours per week or 76 hours a fortnight.</p><p><strong>b.</strong> The ordinary hours shall be 152 hours per four week period, to be worked as 19 shifts each of eight hours duration or by mutual agreement, shifts of not more than ten hours each over four days per week may be worked, provided that the length of any ordinary shift shall not exceed ten hours.</p><p><strong>c.</strong> Subject to sub-clause d, the ordinary hours for a week’s work for a Pharmacist, student Pharmacist or Pharmacist Intern shall be worked between Monday and Friday.</p><p><strong>d.</strong> Effective 1 July 2023, subject to the provisions of <a href="/eba/ebas/mspp/schedules/13-pharmacist-weekend-ordinary-hours.html">Schedule 13</a> – Pharmacist Weekend Ordinary Hours Roster, a Pharmacist, including an Intern and Student Pharmacist, may work ordinary hours on a weekend.</p><p><strong>e.</strong> With the exception of time occupied in having meals, the work of each shift shall be continuous.</p><p><strong>55.2</strong> Arrangement of hours for seven day shift workers Subject to the roster provisions 80 hours may be worked in any two consecutive weeks, provided that no more than 6 shifts can be rostered or worked consecutively in any one week without the Employee being rostered off for a minimum of 24 hours.</p><p><strong>55.3</strong> Nine day fortnight Notwithstanding anything else in this clause, with the agreement of the Employer, a full- time Employee may work nine (9) days within a fortnight with a tenth day as a non-paid day and four rostered days off. Such Employees will not access the ADO provisions outlined in clause 55.4 below and will work longer shifts to allow for the completion of 76 hours in a fortnight. Hours worked in addition to 76 hours per fortnight will be paid as overtime under <a href="/eba/ebas/mspp/hours-of-work/59-overtime.html">clause 59</a>.</p><p><strong>55.4</strong> Accrued Days Off (ADO)</p><p><strong>a.</strong> An Accrued Day Off (ADO) is to accrue for each full-time Employee in accordance with clause 55.4b below.</p><p><strong>b.</strong> Payment for ordinary hours will be for 7 hours 36 minutes each day worked with 24 minutes each day of ordinary duty being accrued towards one paid day off per four week period.</p><p><strong>c.</strong> Provided that where shifts are worked over four days in accordance with 55.1b above, local arrangements will be entered into regarding the accrual of ADOs, such that full-time Employees accrue an ADO over a five week cycle.</p><p><strong>55.5</strong> ADOs and rosters</p><p><strong>a.</strong> Subject to the provisions of <a href="/eba/ebas/mspp/hours-of-work/57-employee-rosters.html">clause 57</a> – Rosters, there shall be a four week (or five weeks in the case of ten hour shifts) roster drawn up showing the days on which the Employee is to work their ordinary hours and the Employee’s accrued days off.</p><p><strong>b.</strong> Each Employee shall take their ADO in accordance with the roster.</p><p><strong>c.</strong> An Employee’s ADO may be changed during the currency of the roster period by agreement between the Employer and Employee. If an ADO is deferred, it shall be taken within the next four week period, unless otherwise agreed. In the absence of agreement, where the day of an ADO is changed by the Employer, <a href="/eba/ebas/mspp/hours-of-work/57-employee-rosters.html">clause 57</a> – Rosters shall apply.</p><p><strong>d.</strong> Where possible the ADO shall be taken in conjunction with the normal rostered day(s) off.</p><p><strong>e.</strong> Any untaken ADOs shall remain to the credit of the Employee and will be paid out on termination of employment.</p><p><strong>f.</strong> Absences on paid leave shall count as time worked for the purposes of accrual of time towards ADOs.</p><p><strong>g.</strong> Where an Employee’s ADO falls on a public holiday prescribed by this Agreement, the ADO shall be taken in lieu thereof at a time agreed between the Employer and Employee. Such day shall be taken within the same four week cycle where practical.</p><p><strong>h.</strong> An Employee may elect, with the consent of the Employer, to take a part ADO.</p><p><strong>i.</strong> An Employer shall record ADO arrangements in the Time and Wages Record pursuant to the Act.</p><p><strong>55.6</strong> Summer Time</p><p><strong>a.</strong> Despite the overtime provisions of this Agreement, if an Employee works on a shift during which time changes because of the introduction of, or cessation to, daylight saving, that Employee will be paid for the actual hours worked at the applicable ordinary time rate of pay (including any applicable shift allowances, allowances ordinarily payable in respect of the shift and special rates for Saturdays and Sundays).</p><p>Example: An Employee is rostered to work a ten hour night shift from 11pm through to 9:30am (including a 30 minute meal break). During the course of this shift, the clock is wound forward one hour due to the commencement of daylight saving. The Employee therefore works nine hours. The Employee is paid nine hours at their ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for Saturdays and Sundays). Example: An Employee is rostered in a ten hour night shift from 11pm through to 9:30am (including a 30 minute meal break). During the course of this shift, the clock is wound back one hour due to the cessation of daylight saving. The Employee therefore works 11 hours. The Employee is paid 11 hours at their ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for Saturdays and Sundays). No overtime is paid for the additional hour worked.</p><p><strong>b.</strong> Despite the above, for the purpose of calculating accrued days off, Employees will be taken to have worked the standard hours for a night shift in accordance with the roster.</p><p>Plain language terms: ordinary hours, weekly hours.</p>',28)])])}const f=o(s,[["render",n]]);export{u as __pageData,f as default};
